SELECT a.HOMEPAGE_ID, a.GROUP_IDX, a.CATEGORY_IDX, a.TRAINING_IDX, a.TRAINING_NAME, a.TRAINING_DESC, a.TRAINING_ETC, a.TRAINING_STAGE, a.TRAINING_TARGET, a.LIMIT_HAK, a.LIMIT_HAK2, a.TRAINING_STATUS, a.TRAINING_LIMIT_COUNT, a.TRAINING_JOIN_UNIT, a.TRAINING_BACKUP_COUNT, a.TRAINING_OFFLINE_COUNT, a.START_JOIN_DATE, a.START_JOIN_TIME, a.END_JOIN_DATE, a.END_JOIN_TIME, a.TRAINING_DAY, a.START_DATE, a.START_TIME, a.TRAINING_COUNT, a.END_DATE, a.END_TIME, a.PLAN_FILE_NAME, a.MEMBER_YN, a.USE_YN, a.CERTIFICATE_YN, a.SURVEY_IDX, a.TRAINING_JOIN_LIMIT_UNIT, a.TRAINING_JOIN_LIMIT_VALUE,TO_CHAR(a.ADD_DATE, 'YYYY-MM-DD') AS ADD_DATE, b.TEACHER_NAME, b.TEACHER_BIRTH, A.family_count_yn, A.agent_yn, A.school_info_yn, A.school_grade_yn, A.remark_yn, c.CATEGORY_NAME, d.GROUP_NAME, a.add_guide, NVL((SELECT COUNT(*) FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TRAINING_IDX), 0) AS TRAINING_JOIN_COUNT, NVL((SELECT COUNT(*) FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND APPLY_STATUS='2' GROUP BY TRAINING_IDX), 0) AS TRAINING_BACKUP_JOIN_COUNT, NVL((SELECT COUNT(*) FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TRAINING_IDX), 0) AS TRAINING_OFF_JOIN_COUNT, a.IMAGE_PLAN_FILE_NAME, a.IMAGE_REAL_FILE_NAME, a.IMAGE_FILE_EXTENSION, a.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak) AS LIMIT_HAK_STR, getCodeIdToCodeName('CMS', 'C0020', a.limit_hak2) AS LIMIT_HAK2_STR, a.neis_location_yn, a.neis_cd_yn, a.neis_training_num_yn, a.large_category_idx, a.organization_yn, a.rank_yn, a.course_taken_yn, (SELECT code_name FROM TRAINING_CODE2 WHERE training_code = a.large_category_idx) as large_category_name, program_classification1, program_classification2, program_classification3, program_subject, program_age_div, (SELECT code_name FROM TRAINING_CODE2 WHERE training_code = a.program_subject) as program_subject_name, (SELECT code_name FROM TRAINING_CODE WHERE large_code = a.program_classification1 AND mid_code = '--' AND small_code = '--') as program_classification1_name, (SELECT code_name FROM TRAINING_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = '--') as program_classification2_name, (SELECT code_name FROM TRAINING_CODE WHERE large_code = a.program_classification1 AND mid_code = a.program_classification2 AND small_code = a.program_classification3) as program_classification3_name, a.qr_check, a.qr_check_count FROM TRAINING a, TRAINING_TEACHER b, TRAINING_CATEGORY c, TRAINING_CATEGORY_GROUP d WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID(+) AND a.TEACHER_IDX = b.TEACHER_IDX(+) AND a.HOMEPAGE_ID = c.HOMEPAGE_ID(+) AND a.GROUP_IDX = c.GROUP_IDX(+) AND a.CATEGORY_IDX = c.CATEGORY_IDX(+) AND a.HOMEPAGE_ID = d.HOMEPAGE_ID(+) AND a.GROUP_IDX = d.GROUP_IDX(+)
