SELECT CASE WHEN TO_DATE(A.end_date || ' ' || A.end_time, 'YYYY-MM-DD HH24:MI') < SYSDATE THEN '9' WHEN A.status = 0 AND A.cancle_use_yn = 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.start_cancle_date || ' ' || A.start_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.end_cancle_date || ' ' || A.end_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.start_date || ' ' || start_time AND A.apply_limit = 'Y' THEN '44' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.training_limit_count > A.training_join_count THEN '0' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.training_limit_count <= A.training_join_count AND A.training_backup_count > A.training_backup_join_count THEN '1' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.training_limit_count <= A.training_join_count AND A.training_backup_count <= A.training_backup_join_count THEN '5' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_start_date THEN '6' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' WHEN A.status = 1 AND A.apply_status = '1' AND (( A.cancle_use_yn != 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date ) OR ( A.cancle_use_yn = 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.start_cancle_date || ' ' || A.start_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.end_cancle_date || ' ' || A.end_cancle_time AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.start_date || ' ' || start_time )) THEN '2' WHEN A.status = 1 AND A.apply_status = '1' AND A.cancle_use_yn = 'Y' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 