SELECT COUNT(*) FROM ( SELECT CASE WHEN TO_DATE(A.end_date || ' ' || A.end_time, 'YYYY-MM-DD HH24:MI') < SYSDATE THEN '9' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.training_limit_count > A.training_join_count THEN '0' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.training_limit_count <= A.training_join_count AND A.training_backup_count > A.training_backup_join_count THEN '1' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date AND A.training_limit_count <= A.training_join_count AND A.training_backup_count <= A.training_backup_join_count THEN '5' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_start_date THEN '6' WHEN A.status = 0 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' WHEN A.status = 1 AND A.apply_status = '1' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '2' WHEN A.status = 1 AND A.apply_status = '2' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '3' WHEN A.status = 1 AND A.apply_status = '99' AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_start_date AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') < A.req_end_date THEN '7' WHEN A.status = 1 AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= A.req_end_date THEN '4' END as TRAINING_STATUS, A.HOMEPAGE_ID, A.GROUP_IDX, A.CATEGORY_IDX, A.TRAINING_IDX, A.TRAINING_NAME, A.TRAINING_DESC, A.TRAINING_ETC, A.TRAINING_STAGE, A.TRAINING_TARGET, A.LIMIT_HAK, a.LIMIT_HAK2, A.TRAINING_LIMIT_COUNT, A.TRAINING_JOIN_UNIT, A.TRAINING_BACKUP_COUNT, A.TRAINING_OFFLINE_COUNT, A.START_JOIN_DATE, A.START_JOIN_TIME, A.END_JOIN_DATE, A.END_JOIN_TI