CATEGORY_NAME,d.GROUP_NAME, a.START_JOIN_DATE||' '||a.START_JOIN_TIME REQ_START_DATE, a.END_JOIN_DATE||' '||a.END_JOIN_TIME REQ_END_DATE, NVL((SELECT COUNT(*) FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND APPLY_STATUS='1' AND APPLY_TYPE != 'CMS' GROUP BY TRAINING_IDX), 0) AS TRAINING_JOIN_COUNT, NVL((SELECT COUNT(*) FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND APPLY_STATUS='2' GROUP BY TRAINING_IDX), 0) AS TRAINING_BACKUP_JOIN_COUNT, NVL((SELECT COUNT(*) FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND APPLY_STATUS='1' AND APPLY_TYPE = 'CMS' GROUP BY TRAINING_IDX), 0) AS TRAINING_OFF_JOIN_COUNT, a.IMAGE_PLAN_FILE_NAME, a.IMAGE_REAL_FILE_NAME, a.IMAGE_FILE_EXTENSION, a.IMAGE_FILE_SIZE, a.LIMIT_HAK_YN, a.family_count_yn, a.agent_yn, a.school_info_yn, a.school_grade_yn, a.remark_yn, a.neis_location_yn, a.neis_cd_yn, a.neis_training_num_yn, a.organization_yn, a.rank_yn, a.course_taken_yn FROM (SELECT * FROM TRAINING WHERE 1 = 1
AND TRAINING_NAME LIKE '%'||#{search_text}||'%'
AND TRAINING_NAME LIKE '%'||#{searchKeyword1}||'%'
${logicFunction1} TRAINING_NAME LIKE '%'||#{searchKeyword2}||'%'
${logicFunction2} TRAINING_NAME LIKE '%'||#{searchKeyword3}||'%'
${logicFunction3} TRAINING_NAME LIKE '%'||#{searchKeyword4}||'%'
AND START_DATE >= #{start_date}
AND START_DATE <= #{end_date}
AND START_JOIN_DATE >= #{start_join_date}
AND START_JOIN_DATE <= #{end_join_date}
AND homepage_id = #{homepage_id}
AND large_category_idx = #{large_category_idx}
AND group_idx = #{group_idx}
AND category_idx = #{category_idx}
AND USE_YN = 'Y' AND DELETE_YN = 'N' ) a, TRAINING_TEACHER b, TRAINING_CATEGORY c, TRAINING_CATEGORY_GROUP d WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID(+) AND a.TEACHER_IDX = b.TEACHER_IDX(+) AND a.HOMEPAGE_ID = c.HOMEPAGE_ID(+) AND a.GROUP_IDX = c.GROUP_IDX(+) AND a.CATEGORY_IDX = c.CATEGORY_IDX(+) AND a.HOMEPAGE_ID = d.HOMEPAGE_ID(+) AND a.GROUP_IDX = d.GROUP_IDX(+) --AND SYSDATE < TO_DATE(a.END_JOIN_DATE||' '||a.END_JOIN_TIME, 'YYYY-MM-DD HH24:MI') ORDER BY ABS(SYSDATE - (TO_DATE(a.START_JOIN_DATE ||' '|| a.START_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, ABS(SYSDATE - (TO_DATE(a.END_JOIN_DATE ||' '|| a.END_JOIN_TIME, 'YYYY-MM-DD HH24:MI'))) ASC, a.PRINT_SEQ ASC ) A )
WHERE
TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI') >= req_end_date
TRAINING_STATUS = #{status}

